select 
from ocr_engine_config


        and (engine_code like #{keywordLike}
        or engine_name like #{keywordLike}
        or engine_type like #{keywordLike}
        or provider like #{keywordLike}
        or base_url like #{keywordLike})


        and provider = #{query.provider}


        and engine_type = #{query.engineType}


        and status = #{query.status}


order by default_engine desc, priority desc, updated_at desc
